## Workbox
```javascript
import {precacheAndRoute, registerRoute, CacheFirst, NetworkFirst} from 'workbox-*';
precacheAndRoute(self.__WB_MANIFEST);
registerRoute(({url}) => url.pathname.startsWith('/api'), new NetworkFirst());
registerRoute(({request}) => request.destination === 'image', new CacheFirst());
```

## Background Sync
```javascript
// Çevrimdışıyken kaydet
navigator.serviceWorker.ready.then(reg =>
  reg.sync.register('form-submit')
);
// SW'de
self.addEventListener('sync', e => {
  if (e.tag === 'form-submit')
    e.waitUntil(sendPendingForms());
});
```

## Renk Sistemi
```css
:root {
  --color-primary-500: #4a9eff;
  --color-success: #22c55e;
  --color-error: #ef4444;
  --color-neutral-100: #f5f5f5;
  --color-neutral-900: #171717;
}
```
Semantik tokenlar (bg-surface, text-primary) kullan.

## Dark Mode Tokenlar
```css
:root {
  --bg: #ffffff;
  --text: #171717;
}
@media (prefers-color-scheme: dark) {
  :root { --bg: #0a0a0a; --text: #ededed; }
}
[data-theme='dark'] { --bg: #0a0a0a; --text: #ededed; }
```

## Tema Toggle
```javascript
function setTheme(theme) {
  document.documentElement.dataset.theme = theme;
  localStorage.setItem('theme', theme);
}
// Init
const saved = localStorage.getItem('theme')
  || (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light');
setTheme(saved);
```

## Dark Mode Görseller
```css
/* SVG ikon rengi */
.icon { fill: var(--text); }
/* Resim parlaklığı */
[data-theme='dark'] img:not([class*='logo']) {
  filter: brightness(0.85);
}
/* Gölge yumuşatma */
[data-theme='dark'] .card {
  box-shadow: 0 4px 24px rgba(0,0,0,.6);
}
```

